#include<bits/stdc++.h>
using namespace std;
int u[100010],v[100010];
bool vis[100010];
vector<int> mp[100010];
int a=-1,b=-1;
int ans[100010],now[100010],tot;
int n,m;
int xiaoyu(int a[],int b[])
{
    for(int i=1;i<=n;i++)
    {
        if(a[i]<b[i])
        {
            return true;
        }
        if(a[i]>b[i])
        {
            return false;
        }
    }
    return false;
}
void dfs(int x)
{
    if(m==n-1)
    {
        printf("%d ",x);
    }
    else
    {
        now[++tot]=x;
    }
    vis[x]=1;
    for(int i:mp[x])
    {
        if(!vis[i]&&(min(x,i)!=min(a,b)||max(x,i)!=max(a,b)))
        {
            dfs(i);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&u[i],&v[i]);
        mp[u[i]].push_back(v[i]);
        mp[v[i]].push_back(u[i]);
    }
    for(int i=1;i<=n;i++)
    {
        sort(mp[i].begin(),mp[i].end());
    }
    if(m==n-1)
    {
        dfs(1);
        return 0;
    }
    for(int i=1;i<=m;i++)
    {
        memset(vis,0,sizeof(vis));
        a=u[i];
        b=v[i];
        tot=0;
        dfs(1);
        if(tot==n&&(ans[1]==0||xiaoyu(now,ans)))
        {
            memcpy(ans,now,sizeof(now));
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d ",ans[i]);
    }
    return 0;
}
